// Mobile Sync Wrapper - Integrate Rate Limiter dengan existing sync functions
// Load AFTER mobile-core.min.js
(function(){if(!window.RateLimiter)return console.warn("[SyncWrapper] RateLimiter not loaded");const e=window.syncSingleExam;window.syncSingleExam=async function(t){if(!window.State||!window.State.user)return void showCustomAlert("Login Dulu","Silakan login terlebih dahulu.","⚠️");console.log("[SyncWrapper] Wrapping syncSingleExam with rate limiter");const i=new Promise((i,n)=>{window.RateLimiter.addToQueue(t.id,async()=>{try{const n=await e.call(this,t);i(n)}catch(e){n(e)}})});return i};const n=window.getExamDataOptimized;window.getExamDataOptimized=async function(e,t,i,o){if(!window.RateLimiter)return n.call(this,e,t,i,o);console.log("[SyncWrapper] Wrapping getExamDataOptimized with rate limiter");const s=new Promise((s,a)=>{window.RateLimiter.addToQueue(e,async()=>{try{const a=await n.call(this,e,t,i,o);s(a)}catch(e){a(e)}})});return s};console.log("[SyncWrapper] ✅ Rate limiter integrated with sync functions")})();
